AISuggestion.sysmlv2:
 package "FullDesign2"  {

	// Imports
	private import ScalarValues::*;
	private import QuantitiesAndUnits::*;
	private import ISO80000::*;
	private import Time::*;

	// Definition of signal types
	item def __type_getCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_putCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_pushCoffeeButton;
	item def __type_pushTeaButton;
	item def __type_getCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_ejectCoin {
		attribute nbOfCoins : Integer;
	}
	item def __type_push;
	item def __type_push;

	// Definition of parts
	part def Block__Wallet {
		attribute nbOfCoins : Integer = 2;
		attribute x : Integer = 1;
		attribute minUserDelay : Integer = 20;
		attribute maxUserDelay : Integer = 40;
		attribute __delay : Duration;

		action def  contentOfWallet {
			in nbOfCoins : Integer
		}

		// Signals
		in item getCoin :  __type_getCoin;

		out item putCoin :  __type_putCoin;


		state entry;
		state main;


		state main {
			accept getCoin(t : __type_getCoin)
			do x = t.nbOfCoins
			do nbOfCoins = nbOfCoins+x
			do compute : contentOfWallet (nbOfCoins) {
				in nbOfCoins = nbOfCoins;
			}
			then main;

			IF (nbOfCoins)>(0)
			do  {

				send putCoin{nbOfCoins : x}
				do __delay = uniform(minUserDelay,maxUserDelay)
				after __delay
				do nbOfCoins = nbOfCoins-x
				do compute : contentOfWallet (nbOfCoins) {
					in nbOfCoins = nbOfCoins;
				}
				then main;

			}

		}

		state entry {
			do compute : contentOfWallet (nbOfCoins) {
				in nbOfCoins = nbOfCoins;
			}
			do nbOfCoins = 2
			then main;

		}
	}

	part def Block__CoffeeMachine {
		attribute teaMinDelay : Integer = 3;
		attribute teaMaxDelay : Integer = 8;
		attribute coffeeMinDelay : Integer = 5;
		attribute coffeeMaxDelay : Integer = 10;
		attribute coinDelay : Integer = 50;
		attribute x : Integer;
		attribute nbOfCoins : Integer = 0;

		action def  beverageReady {
		}

		// Signals
		in item pushCoffeeButton :  __type_pushCoffeeButton;

		in item pushTeaButton :  __type_pushTeaButton;

		in item getCoin :  __type_getCoin;

		out item ejectCoin :  __type_ejectCoin;


		state entry;
		state EjectState;
		state WaitingForSecondCoin;
		state WaitingForFirstCoin;
		state TeaDelivered;
		state Beverage;
		state WaitingForSelection;
		state CoffeeDelivered;


		state EjectState {
			send ejectCoin{nbOfCoins : nbOfCoins}
			do nbOfCoins = 0
			then WaitingForFirstCoin;

		}

		state WaitingForSecondCoin {
			accept getCoin(t : __type_getCoin)
			do x = t.nbOfCoins
			do nbOfCoins = 2
			then Beverage;

			after coinDelay
			then EjectState;

		}

		state entry {
			then WaitingForFirstCoin;

		}

		state WaitingForFirstCoin {
			accept getCoin(t : __type_getCoin)
			do x = t.nbOfCoins
			do nbOfCoins = nbOfCoins+x
			then WaitingForSecondCoin;

		}

		state TeaDelivered {
			then WaitingForFirstCoin;

		}

		state Beverage {
			then WaitingForSelection;

		}

		state WaitingForSelection {
			accept pushCoffeeButton
			do nbOfCoins = 0
			do compute : beverageReady
			then CoffeeDelivered;

			accept pushTeaButton
			do nbOfCoins = 0
			do compute : beverageReady
			then TeaDelivered;

			after coinDelay
			send ejectCoin{nbOfCoins : nbOfCoins}
			do nbOfCoins = 0
			then WaitingForFirstCoin;

		}

		state CoffeeDelivered {
			then WaitingForFirstCoin;

		}
	}

	part def Block__CoffeeButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_push;


		state entry;
		state main;
		state state0;


		state main {
			then state0;

		}

		state entry {
			then main;

		}

		state state0 {
			send push
			after mechanicalDelay
			then main;

		}
	}

	part def Block__TeaButton {
		attribute mechanicalDelay : Integer = 10;

		// Signals
		out item push :  __type_push;


		state entry;
		state main;


		state main {
			send push
			after mechanicalDelay
			then main;

		}

		state entry {
			then main;

		}
	}

	// Usage of parts
	part Wallet : Block__Wallet {
	}

	part CoffeeMachine : Block__CoffeeMachine {
		part CoffeeButton : Block__CoffeeButton;
		part TeaButton : Block__TeaButton;
	}

	// Connection between signals
	enum def CommunicationKind {
		synchronous;
		asynchronous;
	}

	connection def ConnectionInfoSync {
		attribute communicationKind : CommunicationKind;
		attribute isPrivate   : Boolean ;
		attribute isLossy     : Boolean ;
	}


	connection CoffeeButton_push__CoffeeMachine_pushCoffeeButton : ConnectionInfoSync
	connect CoffeeMachine.CoffeeButton.push to CoffeeMachine.pushCoffeeButton  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection Wallet_getCoin__CoffeeMachine_ejectCoin : ConnectionInfoSync
	connect Wallet.getCoin to CoffeeMachine.ejectCoin  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection Wallet_putCoin__CoffeeMachine_getCoin : ConnectionInfoSync
	connect Wallet.putCoin to CoffeeMachine.getCoin  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connection TeaButton_push__CoffeeMachine_pushTeaButton : ConnectionInfoSync
	connect CoffeeMachine.TeaButton.push to CoffeeMachine.pushTeaButton  {
		communicationKind = synchronous;
		isPrivate = true;
		isLossy = false;

	}


}
